import{c as a,Q as t,j as r,m as s}from"./chunks/framework.BPKcPtvA.js";const p=JSON.parse('{"title":"How do I create a release?","description":"","frontmatter":{},"headers":[],"relativePath":"guide/recipes/admin/create-release.md","filePath":"guide/recipes/admin/create-release.md","lastUpdated":1778912818000}'),i={name:"guide/recipes/admin/create-release.md"};function o(l,e,n,d,c,g){return t(),r("div",null,[...e[0]||(e[0]=[s('<h1 id="how-do-i-create-a-release" tabindex="-1">How do I create a release? <a class="header-anchor" href="#how-do-i-create-a-release" aria-label="Permalink to &quot;How do I create a release?&quot;">​</a></h1><div class="tip custom-block"><p class="custom-block-title">Who can do this</p><p><strong>Platform Admin</strong> or <strong>Infra Ops</strong></p></div><p>A release packages a set of service-image and environment-variable changes and ships them through a pipeline of stages (dev → staging → production). Creating one is a two-step wizard: Form → Preview.</p><h2 id="steps" tabindex="-1">Steps <a class="header-anchor" href="#steps" aria-label="Permalink to &quot;Steps&quot;">​</a></h2><ol><li>Open <strong>Releases</strong> in the sidebar and click <strong>New Release</strong>.</li><li>Pick a <strong>release type</strong>: Feature, Patch, Hotfix, or Config.</li><li>Bump the <strong>version</strong> (Major / Minor / Patch) and write <strong>release notes</strong>.</li><li>Select the <strong>services</strong> included and pick the <strong>image tag</strong> for each.</li><li>Add <strong>environment variable changes</strong> (Create / Update / Delete) if any.</li><li>Click <strong>Preview</strong>. The summary shows everything that will change and which environments will be touched.</li><li>Click <strong>Create Release</strong>.</li></ol><h2 id="result" tabindex="-1">Result <a class="header-anchor" href="#result" aria-label="Permalink to &quot;Result&quot;">​</a></h2><p>The release appears on the Releases list with status <strong>Pending</strong>. The pipeline visualisation on the detail page shows the stages and their initial states. Triggers and approvals follow your <a href="./../../admin/release-configuration">release configuration</a>.</p><h2 id="related" tabindex="-1">Related <a class="header-anchor" href="#related" aria-label="Permalink to &quot;Related&quot;">​</a></h2><ul><li><a href="./approve-release-stage">How do I approve a release stage?</a></li><li><a href="./trigger-release-stage">How do I trigger a paused release stage?</a></li><li><a href="./rollback-release">How do I roll back a release?</a></li></ul>',9)])])}const u=a(i,[["render",o]]);export{p as __pageData,u as default};
